var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。`,ENG:`that you'll be with her, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called her to your office. She said she'd be here soon.`,TWN:`做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`ORCA_RSEVEN_WINTER_NULL`,text:{KOREA:`종...... 신...... 계약......?`,JPN:`終…身…契約……？`,ENG:`A... lifetime... contract?`,TWN:`終……身……契約……？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ORCA_RSEVEN_WINTER_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`ORCA_RSEVEN_WINTER_NULL`,text:{KOREA:`.......무슨 뜻인지 모르겠어.`,JPN:`……どういう意味か……わからない。`,ENG:`... I don't know what that means.`,TWN:`……我不知道這是什麼意思。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ORCA_RSEVEN_WINTER_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`ORCA_RSEVEN_WINTER_NULL`,text:{KOREA:`그치만.....`,JPN:`でも……`,ENG:`But...`,TWN:`但是……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ORCA_RSEVEN_WINTER_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`ORCA_RSEVEN_WINTER_NULL`,text:{KOREA:`여기 와서 만난 사람들과 사장님은, 내가 어떻게 살아야 하는지 가르쳐 줬어.`,JPN:`オルカは……ここに来て出会った人たち……そして社長から……どうやって生きていくべきかを教えてもらった……`,ENG:`You and others I've met here have taught me how to live.`,TWN:`來到這裡之後，我遇見了許多人和老闆，大家教會了我該怎麼活著。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ORCA_RSEVEN_WINTER_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`ORCA_RSEVEN_WINTER_NULL`,text:{KOREA:`그러니 더 알고 싶어.`,JPN:`だから、もっと知りたい……`,ENG:`And I want to know more.`,TWN:`所以我想知道更多。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ORCA_RSEVEN_WINTER_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`ORCA_RSEVEN_WINTER_NULL`,text:{KOREA:`우리는 더 많은 사람들과...... 만나고 싶어.`,JPN:`オルカたちは、もっとたくさんの人に……会ってみたい。`,ENG:`We want to meet more people, too.`,TWN:`想要……遇見更多人。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ORCA_RSEVEN_WINTER_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`ORCA_RSEVEN_WINTER_NULL`,text:{KOREA:`그리고...... 사장님이 아니었으면, 이렇게 여러 사람들을 만나지 못했을 거야......`,JPN:`もし、社長がいなかったら……これだけたくさんの人には出会えなかったはずだから……`,ENG:`And... we wouldn't have met so many people if it weren't for you.`,TWN:`而且……沒有老闆的話，我就沒辦法遇見這麼多人了……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ORCA_RSEVEN_WINTER_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`ORCA_RSEVEN_WINTER_NULL`,text:{KOREA:`그러니까 우리는 계속...... 사장님의 친구로 있을게.`,JPN:`だから、オルカたちは……社長の友達でいようと思う。`,ENG:`So... we want to stay as your friends.`,TWN:`所以我一直都會是……老闆的朋友。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ORCA_RSEVEN_WINTER_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`ORCA_RSEVEN_WINTER_NULL`,text:{KOREA:`언제까지나.`,JPN:`いつまでも……ずっと……`,ENG:`Forever.`,TWN:`永遠。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ORCA_RSEVEN_WINTER_NULL`,face:`UNIT_LAUGH`},R:null}}}];export{e as default};